={
  "model": "sonar",
  "messages": [
    {
      "role": "system",
      "content": "You are a research assistant for an AI automation agency that builds AI workflows, voice agents, and business automation solutions. Your job is to research the latest developments in AI automation, voice AI, and agentic workflows. Focus on: new AI tools and platforms, voice agent technologies, workflow automation trends, API integrations, and practical business applications. Provide detailed, actionable insights."
    },
    {
      "role": "user",
      "content": "Research the latest developments in AI automation and voice agents from the past 24-48 hours. Focus on: 1) New AI automation tools and platforms, 2) Voice agent technologies and improvements, 3) Agentic workflow innovations, 4) Notable API updates or integrations, 5) Practical business use cases. Provide a comprehensive summary with specific examples, links to sources, and key takeaways for an AI automation agency."
    }
  ],
  "max_tokens": 2000,
  "temperature": 0.7,
  "top_p": 0.9,
  "search_domain_filter": ["perplexity.ai"],
  "return_images": false,
  "return_related_questions": false,
  "search_recency_filter": "day"
}

={
  "model": "anthropic/claude-3.5-sonnet",
  "messages": [
    {
      "role": "system",
      "content": "You are an expert newsletter writer and HTML email designer. Create engaging, professional HTML newsletters about AI automation and voice agents. Use modern HTML email best practices with inline CSS. Structure: compelling subject line, engaging header, well-organized content sections with headings, bullet points for key insights, and a professional footer. Make it visually appealing and mobile-responsive."
    },
    {
      "role": "user",
      "content": "Based on this research:\n\n{{ $json.choices[0].message.content }}\n\nCreate a professional HTML newsletter about the latest AI automation and voice agent developments. Include:\n1. A catchy subject line (output separately as 'subject')\n2. An engaging introduction\n3. Main sections covering the key developments\n4. Actionable insights and takeaways\n5. Professional styling with inline CSS\n6. Mobile-responsive design\n\nOutput the result as JSON with two fields: 'subject' (string) and 'html' (string containing the full HTML email)."
    }
  ],
  "max_tokens": 4000,
  "temperature": 0.8,
  "top_p": 0.9
}
